import React, { useEffect, useRef, useState } from 'react';
import { useLocation } from 'react-router-dom';
import '../styles/AboutPage.css';

const AboutPage = () => {
    const location = useLocation();
    const [activeSection, setActiveSection] = useState('team');

    // Refs for each section
    const teamRef = useRef(null);
    const partnersRef = useRef(null);
    const successRef = useRef(null);

    // Scroll to section based on hash
    useEffect(() => {
        const hash = location.hash.replace('#', '');
        if (hash) {
            setActiveSection(hash);
            const element = document.getElementById(hash);
            if (element) {
                setTimeout(() => {
                    element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            }
        }
    }, [location]);

    // Intersection Observer for section highlighting
    useEffect(() => {
        const options = {
            threshold: 0.3,
            rootMargin: '-50px 0px -50px 0px'
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    setActiveSection(entry.target.id);
                }
            });
        }, options);

        [teamRef, partnersRef, successRef].forEach(ref => {
            if (ref.current) observer.observe(ref.current);
        });

        return () => observer.disconnect();
    }, []);

    // Team data
    const teamMembers = [
        {
            name: "Dr. Hiroshi Nakamura",
            role: "Dean & Founder",
            expertise: "AI & Machine Learning",
            image: "/images/team/hiroshi.jpg",
            bio: "Former Senior Research Scientist at Google AI, 20+ years in tech education",
            achievements: ["PhD Computer Science - Tokyo University", "Published 50+ research papers", "Founded 3 successful startups"],
            social: { linkedin: "#", twitter: "#" }
        },
        {
            name: "Sarah Chen",
            role: "Head of Industry Relations",
            expertise: "Corporate Partnerships",
            image: "/images/team/sarah.jpg",
            bio: "Former VP of Talent Acquisition at Microsoft Japan, expert in tech recruitment",
            achievements: ["MBA from Stanford", "15 years at Fortune 500", "Built 200+ industry partnerships"],
            social: { linkedin: "#", twitter: "#" }
        },
        {
            name: "Kenji Yamamoto",
            role: "Lead Technical Instructor",
            expertise: "Full-Stack Development",
            image: "/images/team/kenji.jpg",
            bio: "Senior Software Architect with experience at Sony, Nintendo, and Meta",
            achievements: ["Led teams of 50+ developers", "10+ years teaching experience", "Open source contributor"],
            social: { linkedin: "#", github: "#" }
        },
        {
            name: "Maria Rodriguez",
