            expertise: "Career Development",
            image: "/images/team/maria.jpg",
            bio: "Certified career coach specializing in tech transitions and professional development",
            achievements: ["Certified Professional Coach", "500+ successful placements", "Forbes 30 Under 30 Education"],
            social: { linkedin: "#", twitter: "#" }
        }
    ];

