            salary: "Self-employed",
            timeline: "2021 Graduate",
            skills: ["Node.js", "React", "AWS", "Leadership"]
        }
    ];

    const scrollToSection = (sectionId) => {
        const element = document.getElementById(sectionId);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
    };

    return (
        <div className="about-page">
            {/* Hero Section */}
            <section className="about-hero">
                <div className="hero-background">
                    <div className="hero-shape shape-1"></div>
                    <div className="hero-shape shape-2"></div>
                    <div className="hero-shape shape-3"></div>
                </div>
                <div className="container">
                    <div className="hero-content">
                        <span className="hero-badge">About Forum Academy</span>
                        <h1>Shaping the Future of Tech Education</h1>
                        <p>For over 15 years, we've been at the forefront of technology education, connecting talented individuals with industry-leading companies and creating pathways to successful tech careers.</p>

                        <div className="hero-stats">
                            <div className="stat-item">
                                <span className="stat-number">5,000+</span>
                                <span className="stat-label">Graduates Placed</span>
                            </div>
                            <div className="stat-item">
                                <span className="stat-number">200+</span>
                                <span className="stat-label">Industry Partners</span>
                            </div>
                            <div className="stat-item">
                                <span className="stat-number">93%</span>
                                <span className="stat-label">Employment Rate</span>
                            </div>
                        </div>

                        <div className="hero-navigation">
                            <button 
                                className={`nav-button ${activeSection === 'team' ? 'active' : ''}`}
                                onClick={() => scrollToSection('team')}
                            >
                                <span className="material-icons">group</span>
                                Our Team
                            </button>
                            <button 
                                className={`nav-button ${activeSection === 'partners' ? 'active' : ''}`}
                                onClick={() => scrollToSection('partners')}
                            >
                                <span className="material-icons">handshake</span>
