                            </button>
                            <button 
                                className={`nav-button ${activeSection === 'success' ? 'active' : ''}`}
                                onClick={() => scrollToSection('success')}
                            >
                                <span className="material-icons">star</span>
                                Success Stories
                            </button>
                        </div>
                    </div>
                </div>
            </section>

            {/* Our Team Section */}
            <section id="team" className="team-section" ref={teamRef}>
                <div className="container">
                    <div className="section-header">
                        <span className="section-badge">Meet Our Leaders</span>
                        <h2>Expert Team Behind Your Success</h2>
