                                        <span className="stat-label">Graduates Hired</span>
                                    </div>
                                    <div className="stat">
                                        <span className="stat-number">{partner.stats.internships}</span>
                                        <span className="stat-label">Internships</span>
                                    </div>
                                </div>
                            </div>
