                            <div className="benefit-item">
                                <span className="material-icons">work</span>
                                <h4>Direct Hiring Pipeline</h4>
                                <p>Exclusive access to job opportunities and fast-track interview processes</p>
                            </div>
                            <div className="benefit-item">
                                <span className="material-icons">psychology</span>
                                <h4>Mentorship Programs</h4>
                                <p>One-on-one guidance from industry professionals and senior engineers</p>
                            </div>
                            <div className="benefit-item">
                                <span className="material-icons">verified</span>
                                <h4>Industry Certifications</h4>
                                <p>Access to official certification programs and training materials</p>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

