            <section id="success" className="success-section" ref={successRef}>
                <div className="container">
                    <div className="section-header">
                        <span className="section-badge">Success Stories</span>
                        <h2>Where Our Graduates Thrive</h2>
                        <p>Real stories from real graduates who transformed their careers with Forum Academy</p>
                    </div>

                    <div className="success-stories">
                        {successStories.map((story, index) => (
                            <div key={index} className="success-story" style={{ animationDelay: `${index * 0.2}s` }}>
